1	export type Cell = [number, number];
2	
3	export function nextGeneration(cells: Cell[]): Cell[] {
4	  const key = (x: number, y: number) => `${x},${y}`;
5	  const alive = new Set(cells.map(([x, y]) => key(x, y)));
6	
7	  const countNeighbors = (x: number, y: number) => {
8	    let count = 0;
9	    for (let dx = -1; dx <= 1; dx++) {
10	      for (let dy = -1; dy <= 1; dy++) {
11	        if (dx === 0 && dy === 0) continue;
12	        if (alive.has(key(x + dx, y + dy))) count++;
13	      }
14	    }
15	    return count;
16	  };
17	
18	  const result: Cell[] = [];
19	  for (const [x, y] of cells) {
20	    const n = countNeighbors(x, y);
21	    if (n === 2 || n === 3) result.push([x, y]);
22	  }
23	  return result;
24	}
